/*
 * Gantt timeline chart.
 *
 * Input range layout (3 or 4 columns):
 *   [Task]     [Start]       [End | Duration]   [Owner?]
 *   "Design"   2026-01-01    2026-02-15         "Alice"
 *   "Build"    2026-02-10    60                 "Bob"
 *
 * Start is a date. Third column is either an end date or a duration in days
 * (auto-detected: small numbers are durations, larger / date-shaped values
 * are end dates).
 */

import { readActiveSelection, RangeSnapshot } from "../core/data";
import { activePalette } from "../core/style";
import {
  openSvg,
  closeSvg,
  title,
  rect,
  text,
  line,
  DEFAULT_SIZE,
  DEFAULT_MARGINS,
  seriesColor,
} from "./svgPrimitives";
import { upsertSvgShape } from "./svgHost";
import { RegisteredBinding } from "../core/bindings";

interface Task {
  name: string;
  start: number; // ms epoch
  end: number;
  owner?: string;
}

function toDate(v: unknown): number | null {
  if (v == null || v === "") return null;
  if (typeof v === "number") {
    // Excel serial date — days since 1899-12-30
    if (v > 1 && v < 80000) {
      return new Date(Date.UTC(1899, 11, 30) + v * 86400000).getTime();
    }
    return null;
  }
  const t = Date.parse(String(v));
  return Number.isFinite(t) ? t : null;
}

function buildTasks(snap: RangeSnapshot): Task[] {
  const tasks: Task[] = [];
  for (let r = 1; r < snap.rowCount; r++) {
    const row = snap.values[r];
    const name = String(row[0] ?? "");
    const start = toDate(row[1]);
    if (start === null) continue;
    let end: number | null = null;
    const third = row[2];
    if (typeof third === "number" && third < 1000) {
      // treat as duration in days
      end = start + third * 86400000;
    } else {
      end = toDate(third);
    }
    if (end === null) continue;
    const owner = row[3] != null ? String(row[3]) : undefined;
    tasks.push({ name, start, end, owner });
  }
  return tasks;
}

function formatDateShort(ms: number): string {
  const d = new Date(ms);
  return `${d.getUTCFullYear()}-${String(d.getUTCMonth() + 1).padStart(2, "0")}-${String(d.getUTCDate()).padStart(2, "0")}`;
}

export function renderGanttSvg(snap: RangeSnapshot, opts?: { titleText?: string }): string {
  const tasks = buildTasks(snap);
  if (tasks.length === 0) throw new Error("Gantt needs Task, Start, End/Duration columns.");

  const palette = activePalette();
  const { width, height } = DEFAULT_SIZE;
  const m = { ...DEFAULT_MARGINS, left: 120 };
  const plotW = width - m.left - m.right;
  const plotH = height - m.top - m.bottom;

  const minDate = Math.min(...tasks.map((t) => t.start));
  const maxDate = Math.max(...tasks.map((t) => t.end));
  const span = maxDate - minDate;
  const xOf = (ms: number) => m.left + ((ms - minDate) / span) * plotW;

  const rowH = plotH / tasks.length;
  const barH = Math.min(22, rowH * 0.6);

  let svg = openSvg();
  svg += title(opts?.titleText ?? "Gantt", { width, height });

  // Time axis ticks: pick 6 nicely-spaced dates
  const tickCount = 6;
  for (let i = 0; i <= tickCount; i++) {
    const t = minDate + (i / tickCount) * span;
    const x = xOf(t);
    svg += line(x, m.top, x, m.top + plotH, "#EEE", { width: 1 });
    svg += text(x, m.top + plotH + 16, formatDateShort(t), { fill: "#666", size: 10 });
  }

  // Bars
  tasks.forEach((t, i) => {
    const y = m.top + i * rowH + (rowH - barH) / 2;
    const x1 = xOf(t.start);
    const x2 = xOf(t.end);
    const color = seriesColor(i, palette);
    svg += rect(x1, y, Math.max(2, x2 - x1), barH, color, { rx: 3 });
    svg += text(m.left - 8, y + barH / 2 + 3, t.name, { anchor: "end", size: 11, fill: "#333" });
    if (t.owner) {
      svg += text(x2 + 4, y + barH / 2 + 3, t.owner, { anchor: "start", size: 10, fill: "#666" });
    }
  });

  svg += line(m.left, m.top + plotH, m.left + plotW, m.top + plotH, "#CCC");
  svg += closeSvg();
  return svg;
}

export async function insertGantt(): Promise<void> {
  const snap = await readActiveSelection();
  const svg = renderGanttSvg(snap);
  await upsertSvgShape(svg, "gantt", snap);
}

export async function renderGantt(snap: RangeSnapshot, binding: RegisteredBinding): Promise<void> {
  const svg = renderGanttSvg(snap);
  await upsertSvgShape(svg, "gantt", snap, binding);
}
