/*
 * Utilities for pulling and parsing range data from Excel and watching for changes.
 */

/* global Excel */

export interface RangeSnapshot {
  address: string; // sheet-qualified
  sheetName: string;
  values: (string | number | boolean | null)[][];
  rowCount: number;
  columnCount: number;
}

export async function readActiveSelection(): Promise<RangeSnapshot> {
  return Excel.run(async (ctx) => {
    const range = ctx.workbook.getSelectedRange();
    range.load(["values", "address", "rowCount", "columnCount", "worksheet/name"]);
    await ctx.sync();
    return {
      address: range.address,
      sheetName: range.worksheet.name,
      values: range.values,
      rowCount: range.rowCount,
      columnCount: range.columnCount,
    };
  });
}

export async function readRange(sheetName: string, address: string): Promise<RangeSnapshot> {
  return Excel.run(async (ctx) => {
    const sheet = ctx.workbook.worksheets.getItem(sheetName);
    const range = sheet.getRange(address);
    range.load(["values", "address", "rowCount", "columnCount"]);
    await ctx.sync();
    return {
      address: range.address,
      sheetName,
      values: range.values,
      rowCount: range.rowCount,
      columnCount: range.columnCount,
    };
  });
}

/**
 * Parse a typical 2D range where the top row is column headers and left
 * column is category labels. Returns categories, series names, and a
 * numeric matrix.
 */
export interface ParsedTable {
  categories: string[];
  series: string[];
  matrix: number[][]; // [row][col] numeric, NaN where missing
  totals: { row: number[]; column: number[] };
}

export function parseTable(snap: RangeSnapshot): ParsedTable {
  if (snap.rowCount < 2 || snap.columnCount < 2) {
    throw new Error("Selection must be at least 2x2 with headers.");
  }
  const headerRow = snap.values[0];
  const series = headerRow.slice(1).map((v) => String(v ?? ""));
  const categories: string[] = [];
  const matrix: number[][] = [];

  for (let r = 1; r < snap.rowCount; r++) {
    const row = snap.values[r];
    categories.push(String(row[0] ?? ""));
    const nums: number[] = [];
    for (let c = 1; c < snap.columnCount; c++) {
      const v = row[c];
      const n = typeof v === "number" ? v : Number(v);
      nums.push(Number.isFinite(n) ? n : NaN);
    }
    matrix.push(nums);
  }

  const rowTotals = matrix.map((row) => row.reduce((s, v) => s + (Number.isFinite(v) ? v : 0), 0));
  const colTotals = series.map((_, c) =>
    matrix.reduce((s, row) => s + (Number.isFinite(row[c]) ? row[c] : 0), 0)
  );

  return { categories, series, matrix, totals: { row: rowTotals, column: colTotals } };
}

export function sum(values: number[]): number {
  return values.reduce((s, v) => s + (Number.isFinite(v) ? v : 0), 0);
}

export function cagr(start: number, end: number, years: number): number {
  if (start <= 0 || years <= 0) return NaN;
  return Math.pow(end / start, 1 / years) - 1;
}
