/*
 * Waterfall (bridge) chart.
 *
 * Input range layout (2 columns):
 *   [Label]      [Value]
 *   "Start"      120
 *   "Q1 wins"     25
 *   "Q2 wins"     18
 *   "Churn"      -15
 *   "End"         -          (blank cell = treat as total/subtotal)
 *
 * Negative values are rendered red, positives green, and totals/subtotals
 * (rows with a blank value) span from 0 to the running sum.
 */

import { readActiveSelection, RangeSnapshot } from "../core/data";
import { activePalette } from "../core/style";
import {
  openSvg,
  closeSvg,
  title,
  rect,
  text,
  line,
  formatNumber,
  niceTicks,
  DEFAULT_SIZE,
  DEFAULT_MARGINS,
} from "./svgPrimitives";
import { upsertSvgShape } from "./svgHost";
import { RegisteredBinding } from "../core/bindings";

interface Bar {
  label: string;
  start: number;
  end: number;
  delta: number;
  kind: "positive" | "negative" | "total";
}

function computeBars(snap: RangeSnapshot): Bar[] {
  const bars: Bar[] = [];
  let running = 0;
  for (let r = 1; r < snap.rowCount; r++) {
    const row = snap.values[r];
    const label = String(row[0] ?? "");
    const raw = row[1];
    const isTotal = raw === null || raw === "" || raw === undefined;
    if (isTotal) {
      bars.push({ label, start: 0, end: running, delta: running, kind: "total" });
    } else {
      const v = typeof raw === "number" ? raw : Number(raw);
      const next = running + (Number.isFinite(v) ? v : 0);
      bars.push({
        label,
        start: running,
        end: next,
        delta: v,
        kind: v >= 0 ? "positive" : "negative",
      });
      running = next;
    }
  }
  return bars;
}

export function renderWaterfallSvg(snap: RangeSnapshot, opts?: { titleText?: string }): string {
  const bars = computeBars(snap);
  if (bars.length === 0) throw new Error("Waterfall requires at least one data row.");

  const palette = activePalette();
  const { width, height } = DEFAULT_SIZE;
  const m = { ...DEFAULT_MARGINS };

  const plotW = width - m.left - m.right;
  const plotH = height - m.top - m.bottom;

  // Y scale
  const allValues = bars.flatMap((b) => [b.start, b.end]);
  const yMin = Math.min(0, ...allValues);
  const yMax = Math.max(0, ...allValues);
  const ticks = niceTicks(yMin, yMax, 6);
  const yScale = (v: number) => m.top + plotH - ((v - ticks.min) / (ticks.max - ticks.min)) * plotH;

  // X scale
  const barCount = bars.length;
  const slotW = plotW / barCount;
  const barW = slotW * 0.62;

  let svg = openSvg();
  svg += title(opts?.titleText ?? "Waterfall", { width, height });

  // grid lines + tick labels
  ticks.ticks.forEach((t) => {
    const y = yScale(t);
    svg += line(m.left, y, m.left + plotW, y, "#EEE", { width: 1 });
    svg += text(m.left - 6, y + 3, formatNumber(t), { anchor: "end", fill: "#666" });
  });

  // zero line
  if (ticks.min < 0 && ticks.max > 0) {
    const zy = yScale(0);
    svg += line(m.left, zy, m.left + plotW, zy, "#999", { width: 1 });
  }

  // bars + connectors
  bars.forEach((b, i) => {
    const cx = m.left + slotW * i + slotW / 2;
    const bx = cx - barW / 2;
    const top = yScale(Math.max(b.start, b.end));
    const bottom = yScale(Math.min(b.start, b.end));
    const h = Math.max(1, bottom - top);
    const color = b.kind === "total" ? palette.accent : b.kind === "positive" ? palette.positive : palette.negative;

    svg += rect(bx, top, barW, h, color, { rx: 2 });

    // value label
    const labelY = top - 4;
    const valueText = b.kind === "total" ? formatNumber(b.end) : (b.delta >= 0 ? "+" : "") + formatNumber(b.delta);
    svg += text(cx, labelY, valueText, { size: 11, weight: "600", fill: color });

    // category label
    svg += text(cx, m.top + plotH + 18, b.label, { size: 10, fill: "#333" });

    // connector to next bar
    if (i < bars.length - 1) {
      const next = bars[i + 1];
      const cy = yScale(b.end);
      const nx = m.left + slotW * (i + 1) + slotW / 2 - barW / 2;
      svg += line(bx + barW, cy, nx, cy, "#999", { width: 1, dash: "3,3" });
      // suppress unused variable warnings
      void next;
    }
  });

  // axes
  svg += line(m.left, m.top, m.left, m.top + plotH, "#CCC", { width: 1 });
  svg += line(m.left, m.top + plotH, m.left + plotW, m.top + plotH, "#CCC", { width: 1 });

  svg += closeSvg();
  return svg;
}

export async function insertWaterfall(): Promise<void> {
  const snap = await readActiveSelection();
  if (snap.columnCount < 2) throw new Error("Select at least 2 columns: Label, Value.");
  const svg = renderWaterfallSvg(snap);
  await upsertSvgShape(svg, "waterfall", snap);
}

/** Re-render an existing waterfall binding from new data. */
export async function renderWaterfall(snap: RangeSnapshot, binding: RegisteredBinding): Promise<void> {
  const svg = renderWaterfallSvg(snap);
  await upsertSvgShape(svg, "waterfall", snap, binding);
}

