/*
 * Ribbon command handlers. Each function is referenced by name in manifest.xml
 * (<Action xsi:type="ExecuteFunction"><FunctionName>...</FunctionName></Action>).
 */

import { insertWaterfall as _waterfall } from "../charts/waterfall";
import { insertMekko as _mekko } from "../charts/mekko";
import { insertGantt as _gantt } from "../charts/gantt";
import { insertButterfly as _butterfly } from "../charts/butterfly";
import { addCagrArrow as _cagr, addStackTotals as _totals } from "../charts/annotations";
import { applyCorporateStyle as _style, cleanupChart as _cleanup } from "../core/format";

/* global Office */

Office.onReady(() => {
  // commands.html stays empty; ribbon buttons call the registered functions.
});

const wrap = (fn: () => Promise<void>) => async (event: Office.AddinCommands.Event) => {
  try {
    await fn();
  } catch (e) {
    // eslint-disable-next-line no-console
    console.error("SharpCell command failed", e);
  } finally {
    event.completed();
  }
};

const insertWaterfall = wrap(_waterfall);
const insertMekko = wrap(_mekko);
const insertGantt = wrap(_gantt);
const insertButterfly = wrap(_butterfly);
const addCagrArrow = wrap(_cagr);
const addStackTotals = wrap(_totals);
const applyCorporateStyle = wrap(_style);
const cleanupChart = wrap(_cleanup);

// Office requires these symbols on the global scope so the ribbon can find them by name.
declare const window: { [key: string]: unknown };
Office.actions.associate("insertWaterfall", insertWaterfall);
Office.actions.associate("insertMekko", insertMekko);
Office.actions.associate("insertGantt", insertGantt);
Office.actions.associate("insertButterfly", insertButterfly);
Office.actions.associate("addCagrArrow", addCagrArrow);
Office.actions.associate("addStackTotals", addStackTotals);
Office.actions.associate("applyCorporateStyle", applyCorporateStyle);
Office.actions.associate("cleanupChart", cleanupChart);
